import React, { useState, useContext, useEffect, useCallback } from "react";
import axios from "axios";
import { AuthContext } from "../context/AuthContext";
import StudyRoom from "../components/StudyRoom";

const API = axios.create({
    baseURL: "http://localhost:5000/api",
});

API.interceptors.request.use((config) => {
    const token = localStorage.getItem("token");
    if (token) {
        config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
});

const Dashboard = () => {
    const { token } = useContext(AuthContext);
    const [syllabus, setSyllabus] = useState("");
    const [examDate, setExamDate] = useState("");
    const [tasks, setTasks] = useState([]);
    const [activeTask, setActiveTask] = useState(null);

    const fetchTasks = useCallback(async () => {
        try {
            const res = await API.get("/tasks");
            setTasks(res.data);
        } catch (err) {
            console.error("Error fetching tasks:", err);
        }
    }, []);

    useEffect(() => {
        if (token) {
            fetchTasks();
        }
    }, [token, fetchTasks]);

    const handleCreatePlan = async () => {
        try {
            await API.post("/plan/create", { syllabus, examDate });
            alert("AI has generated your timetable!");
            fetchTasks();
        } catch (err) {
            console.error("Error creating plan:", err);
        }
    };

    const handleCompleteTask = async (taskId) => {
        try {
            await API.put(`/tasks/${taskId}`, { status: "completed" });
            alert("Topic completed!");
            setActiveTask(null);
            fetchTasks();
        } catch (err) {
            console.error("Error updating task:", err);
        }
    };

    if (activeTask) {
        return (
            <div className="min-h-screen bg-gray-50 p-5">
                <button 
                    onClick={() => setActiveTask(null)} 
                    className="mb-4 text-blue-600 underline"
                >
                    ← Back to Dashboard
                </button>
                <StudyRoom task={activeTask} onComplete={handleCompleteTask} />
            </div>
        );
    }

    return (
        <div className="p-10 max-w-4xl mx-auto">
            <h1 className="text-3xl font-bold mb-6 text-blue-800">StudyPulse</h1>
            
            <div className="bg-white p-6 rounded-lg shadow-md mb-10 border">
                <h2 className="text-xl font-semibold mb-4">Input Syllabus</h2>
                <div className="flex flex-col gap-4">
                    <textarea 
                        placeholder="Enter topics separated by commas..."
                        value={syllabus}
                        onChange={(e) => setSyllabus(e.target.value)}
                        className="border-2 p-3 rounded-md h-32 outline-none focus:border-blue-500"
                    />
                    <div className="flex items-center gap-4">
                        <label className="font-medium">Exam Date:</label>
                        <input 
                            type="date" 
                            onChange={(e) => setExamDate(e.target.value)}
                            className="border p-2 rounded-md"
                        />
                    </div>
                    <button 
                        onClick={handleCreatePlan} 
                        className="bg-blue-600 text-white font-bold py-3 rounded-md hover:bg-blue-700 transition"
                    >
                        Generate AI Schedule
                    </button>
                </div>
            </div>

            <div className="grid gap-4">
                <h2 className="text-2xl font-semibold">Your Schedule</h2>
                {tasks.length > 0 ? tasks.map(task => (
                    <div key={task._id} className="bg-white border-l-4 border-blue-500 p-4 rounded shadow-sm flex justify-between items-center">
                        <div>
                            <h3 className="font-bold text-lg">{task.title}</h3>
                            <p className="text-gray-500">{new Date(task.date).toLocaleDateString()}</p>
                            <span className={`text-xs font-bold uppercase ${task.status === 'completed' ? 'text-green-500' : 'text-orange-500'}`}>
                                {task.status}
                            </span>
                        </div>
                        {task.status !== 'completed' && (
                            <button 
                                onClick={() => setActiveTask(task)}
                                className="bg-green-500 text-white px-4 py-2 rounded-lg font-medium hover:bg-green-600 transition"
                            >
                                Start Studying
                            </button>
                        )}
                    </div>
                )) : (
                    <p className="text-gray-400 italic">No tasks found. Create a plan to begin.</p>
                )}
            </div>
        </div>
    );
};

export default Dashboard;
